      <p>
        Every tasker is carefully vetted, background-checked, and selected to ensure you receive reliable and high-quality service.
      </p>
    </h5>

    <h5>
      Reliable Support, Anytime
      <p>
        Our dedicated support team is always ready to assist you—before, during, and after your service experience.
      </p>
    </h5>
  </div>
</div>



    </>
  );
};



function Login({ setShowLogin }) {
  const { login } = useAuth();


  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("client");

  const handleLogin = async () => {
    try {
      const res = await fetch("http://localhost:5000/api/auth/login", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();

      if (res.ok) {
        // store role also (important)
        login({ ...data, email, role });

        // redirect based on role
        if (role === "client") navigate("/client");
        else if (role === "tasker") navigate("/tasker");
        else navigate("/admin");
      } else {
        alert(data.message);
      }
    } catch (err) {
      alert("Error logging in");
    }
  };

  return (
    <div>
      <h2>Login</h2> 
     <button onClick={() => setShowLogin(false)}>
  Back to Home
</button>

      <input
        type="email"
        placeholder="Email"
        value={email}
        onChange={(e) => setEmail(e.target.value)} />

      <input
        type="password"
        placeholder="Password"
        value={password}
        onChange={(e) => setPassword(e.target.value)} />

      <select value={role} onChange={(e) => setRole(e.target.value)}>
        <option value="client">Client</option>
        <option value="tasker">Tasker</option>
        <option value="admin">Admin</option>
      </select>

      <button onClick={handleLogin}>Login</button>
    </div>
  );
}

const Client = () => <h2>Client Dashboard</h2>;
const Tasker = () => <h2>Tasker Dashboard</h2>;
const Admin = () => <h2>Admin Dashboard</h2>;

export default function App() {
  const [showLogin, setShowLogin] = useState(false);

  return (
    <AuthProvider>
      <BrowserRouter>
        <Routes>
          <Route
            path="/"
            element={
              showLogin ? (
                <Login setShowLogin={setShowLogin} />
              ) : (
                <Home setShowLogin={setShowLogin} />
              )
            }
          />

          <Route
            path="/login"
            element={<Login setShowLogin={setShowLogin} />}
          />

          <Route element={<ProtectedRoute role="client" />}>
            <Route path="/client" element={<Client />} />
          </Route>

          <Route element={<ProtectedRoute role="tasker" />}>
            <Route path="/tasker" element={<Tasker />} />
          </Route>

          <Route element={<ProtectedRoute role="admin" />}>
            <Route path="/admin" element={<Admin />} />
          </Route>
        </Routes>
      </BrowserRouter>
    </AuthProvider>
  );

}
